SELECT editors.editor_name, roles.role_name
FROM editors
JOIN roles ON editors.role_id = roles.role_id;

SELECT release_id, release_version
FROM version_releases
WHERE release_status = 'draft';

SELECT vr.release_version, vr.release_date, e.editor_name 
FROM version_releases vr 
JOIN editors e ON vr.editor_id = e.editor_id;

SELECT * 
FROM version_releases 
ORDER BY release_date DESC;

SELECT e.editor_name, vr.release_version
FROM editors e
JOIN version_releases vr ON e.editor_id = vr.editor_id;

SELECT vr.release_version
FROM version_releases vr
JOIN release_dependencies rd ON vr.release_id = rd.release_id;

SELECT COUNT(*) AS total_archived_releases
FROM version_releases
WHERE release_status = 'archived';

SELECT e.editor_name
FROM editors e
WHERE LENGTH(e.email) = (SELECT MAX(LENGTH(email)) FROM editors);

SELECT editors.editor_name, editors.editor_id
FROM editors
JOIN editor_release_history ON editors.editor_id = editor_release_history.editor_id;

SELECT vr.release_id, vr.release_version, erh.history_id, erh.editor_id
FROM version_releases vr
INNER JOIN editor_release_history erh ON vr.release_id = erh.release_id;

SELECT release_status, COUNT(*) as release_count
FROM version_releases
GROUP BY release_status;

WITH total_releases AS (
    SELECT COUNT(*) AS total_releases
    FROM version_releases
),
average_note_length AS (
    SELECT AVG(LENGTH(release_notes)) AS avg_note_length
    FROM version_releases
)
SELECT total_releases, avg_note_length
FROM total_releases, average_note_length;

SELECT DISTINCT release_notes
FROM version_releases
WHERE release_status = 'published';
